const raw = $input.first().json?.body || $input.first().json?.data || $input.first().json?.response || '';
const body = typeof raw === 'string' ? raw : (raw && raw.toString ? raw.toString() : '');
const today = new Date().toISOString().slice(0, 10);
const items = [];
try {
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let itemMatch;
  while ((itemMatch = itemRegex.exec(body)) !== null && items.length < 100) {
    const block = itemMatch[1];
    const title = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/i) || [])[1];
    const link = (block.match(/<link[^>]*>([\s\S]*?)<\/link>/i) || block.match(/<link[^>]*href="([^"]+)"/i) || [])[1];
    const desc = (block.match(/<description[^>]*>([\s\S]*?)<\/description>/i) || [])[1] || '';
    const titleText = (title || '').replace(/<!\[CDATA\[|\]\]>/g, '').replace(/&amp;#39;/g, "'").replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();
    const linkText = (link || '').trim();
    if (!titleText || !linkText) continue;
    let niche = 'productivity';
    const nicheList = ['productivity', 'finance', 'home', 'health', 'tech'];
    const descL = (desc || '').toLowerCase();
    for (const n of nicheList) { if (descL.includes(n) || titleText.toLowerCase().includes(n)) { niche = n; break; } }
    items.push({ product_name: titleText, platform: 'Muncheye', commission: '', url: linkText, niche, score: 0, date_found: today, status: 'active' });
  }
} catch (e) { items.length = 0; }
return items.map(i => ({ json: i }));

const item = $input.first().json;
const status = item.statusCode || item.status || '';
const msg = item.message || item.error || ('HTTP ' + status);
return [{ json: { success: false, data: null, error: { code: 'HTTP_ERROR', message: String(msg) } } }];

const items = $input.all().map(i => i.json);
const seen = new Set();
const out = [];
for (const row of items) {
  const key = (row.url || '').trim() || (row.product_name || '').trim();
  if (!key || seen.has(key)) continue;
  seen.add(key);
  out.push(row);
}
return out.map(o => ({ json: o }));
